  async function syncArchivedChatsToDb(forceFullSync = false) {
    const { saveChats: saveChats2 } = await Promise.resolve().then(() => (init_chatDb(), chatDb_exports));
    const { useChatStore: useChatStore2 } = await Promise.resolve().then(() => (init_chatStore(), chatStore_exports));
    const lastSyncKey = "lastSyncedArchivedConversation";
    let lastSynced = forceFullSync ? null : localStorage.getItem(lastSyncKey);
    let lastSyncedDate = lastSynced ? new Date(lastSynced) : null;
    let newestDate = null;
    let allArchivedMetas = [];
    let hasNextPage = true;
    let cursor = null;
    const limit = 100;
    while (hasNextPage) {
      const result = await fetchConversationsPageGraphQL(
        limit,
        cursor,
        "updated",
        false,
        true
      );
      allArchivedMetas.push(...result.items);
      hasNextPage = result.hasNextPage;
      cursor = result.endCursor;
    }
    let toSyncArchivedMetas = allArchivedMetas.filter((meta) => {
      const updateTime = meta.updateTime || meta.update_time;
      const createTime = meta.createTime || meta.create_time;
      const updateDate = updateTime ? new Date(updateTime) : null;
      const createDate = createTime ? new Date(createTime) : null;
      if (!lastSyncedDate) return true;
      return updateDate && updateDate > lastSyncedDate || createDate && createDate > lastSyncedDate;
    });
    for (const meta of allArchivedMetas) {
      const updateTime = meta.updateTime || meta.update_time;
      const createTime = meta.createTime || meta.create_time;
      const updateDate = updateTime ? new Date(updateTime) : null;
      const createDate = createTime ? new Date(createTime) : null;
      if (updateDate && (!newestDate || updateDate > newestDate))
        newestDate = updateDate;
      if (createDate && (!newestDate || createDate > newestDate))
        newestDate = createDate;
    }
    toSyncArchivedMetas.sort((a, b) => {
      const aTime = new Date(
        a.updateTime || a.update_time || a.createTime || a.create_time
      ).getTime();
      const bTime = new Date(
        b.updateTime || b.update_time || b.createTime || b.create_time
      ).getTime();
      return bTime - aTime;
    });
    const totalArchivedConversations = toSyncArchivedMetas.length;
    let syncedCount = 0;
    if (totalArchivedConversations === 0) {
      return;
    }
    const setState = useChatStore2.getState().setState;
    setState({
      syncProgress: {
        total: totalArchivedConversations,
        synced: 0,
        inProgress: true,
        message: instance.t("chat:sync.syncingArchived")
      }
    });
    try {
      for (const meta of toSyncArchivedMetas) {
        const archivedMeta = { ...meta, is_archived: true };
        await saveChats2([archivedMeta]);
        syncedCount++;
        setState({
          syncProgress: {
            total: totalArchivedConversations,
            synced: syncedCount,
            inProgress: true,
            message: `Synced ${syncedCount}/${totalArchivedConversations} archived conversations`
          }
        });
        await new Promise((resolve) => setTimeout(resolve, 50));
      }
      if (newestDate) {
        localStorage.setItem(lastSyncKey, newestDate.toISOString());
      }
    } catch (err) {
    } finally {
      setState({
        syncProgress: {
          total: totalArchivedConversations,
          synced: syncedCount,
          inProgress: false,
          message: `Synced ${syncedCount}/${totalArchivedConversations} archived conversations`
        }
      });
    }
  }
