  async function getProjects(conversationsPerGizmo) {
    const { accessToken } = await chrome.storage.sync.get(["accessToken"]);
    if (!accessToken) {
      throw new Error("No accessToken found in chrome.storage.sync");
    }
    let baseUrl = "https://chatgpt.com/backend-api/gizmos/snorlax/sidebar?owned_only=true";
    if (conversationsPerGizmo !== void 0 && conversationsPerGizmo !== null) {
      baseUrl += `&conversations_per_gizmo=${conversationsPerGizmo}`;
    }
    const allItems = [];
    let cursor = null;
    let hasMore = true;
    while (hasMore) {
      let url = baseUrl;
      if (cursor) {
        url += `&cursor=${encodeURIComponent(cursor)}`;
      }
      const response = await fetch(url, {
        method: "GET",
        credentials: "include",
        headers: {
          Authorization: `Bearer ${accessToken}`,
          "Content-Type": "application/json"
        }
      });
      if (!response.ok) {
        logger.error("Failed to fetch projects", {
          status: response.status,
          statusText: response.statusText,
          url
        });
        break;
      }
      const data = await response.json();
      const items = data.items || [];
      allItems.push(...items);
      cursor = data.cursor || null;
      hasMore = !!cursor;
      logger.debug(
        `\u{1F4E6} [CHATGPT-API] Fetched ${items.length} projects, total: ${allItems.length}, hasMore: ${hasMore}`
      );
    }
    const enrichedItems = await Promise.all(
      allItems.map(async (item) => {
        const gizmo = item.gizmo;
        const gizmoId = gizmo?.id;
        if (!gizmoId) return item;
        try {
          const gptDetailUrl = `https://chatgpt.com/backend-api/gizmos/${gizmoId}`;
          const gptResponse = await fetch(gptDetailUrl, {
            method: "GET",
            credentials: "include",
            headers: {
              Authorization: `Bearer ${accessToken}`,
              "Content-Type": "application/json"
            }
          });
          if (gptResponse.ok) {
            const gptData = await gptResponse.json();
            const profilePictureUrl = gptData.gizmo?.display?.profile_picture_url;
            if (profilePictureUrl) {
              return {
                ...item,
                gizmo: {
                  ...gizmo,
                  display: {
                    ...gizmo.display,
                    profile_picture_url: profilePictureUrl
                  }
                }
              };
            }
          }
        } catch (err) {
        }
        return item;
      })
    );
    return enrichedItems;
  }
