  async function getProjectConversationsGraphql(gizmoId, first = 100, after = null, order = "updated") {
    const { accessToken } = await chrome.storage.sync.get(["accessToken"]);
    if (!accessToken) {
      throw new Error("No accessToken found in chrome.storage.sync");
    }
    const url = new URL("https://chatgpt.com/graphql");
    const variables = {
      gizmoId,
      first,
      after,
      order
    };
    const extensions = {
      persistedQuery: {
        sha256Hash: "5f5770417560c56ba8fa929b84900b53f40cdcc3906d5197003e9ecf7adf3bb7",
        // Mogelijk andere hash nodig
        version: 1
      }
    };
    url.searchParams.append("variables", JSON.stringify(variables));
    url.searchParams.append("extensions", JSON.stringify(extensions));
    try {
      const response = await fetch(url.toString(), {
        method: "GET",
        headers: {
          Authorization: `Bearer ${accessToken}`,
          "Content-Type": "application/json"
        }
      });
      if (!response.ok) {
        return { items: [], hasNextPage: false, endCursor: null };
      }
      const data = await response.json();
      let items = [];
      let pageInfo = { hasNextPage: false, endCursor: null };
      if (data.data?.conversationDisplayHistory) {
        items = data.data.conversationDisplayHistory.edges.map(
          (edge) => edge.node
        );
        pageInfo = data.data.conversationDisplayHistory.pageInfo;
      } else if (data.data?.gizmoConversations) {
        items = data.data.gizmoConversations.edges?.map((edge) => edge.node) || data.data.gizmoConversations.items || [];
        pageInfo = data.data.gizmoConversations.pageInfo || {
          hasNextPage: false,
          endCursor: null
        };
      } else if (data.data?.items) {
        items = data.data.items;
      }
      return {
        items,
        hasNextPage: pageInfo.hasNextPage,
        endCursor: pageInfo.endCursor
      };
    } catch (err) {
      return { items: [], hasNextPage: false, endCursor: null };
    }
  }
  async function getProjectConversations(projectId, lastSyncedDate) {
    const normalizedProjectId = projectId.startsWith("g-p-") ? projectId.replace(/^g-p-/, "") : projectId;
    async function getProjectConversationsPerCursor(cursor = null) {
      try {
        const url = new URL(
          `https://${window.location.host}/backend-api/gizmos/g-p-${normalizedProjectId}/conversations`
        );
        url.searchParams.append("cursor", cursor || "0");
        const { accessToken } = await chrome.storage.sync.get(["accessToken"]);
        if (!accessToken) {
          throw new Error("No accessToken found in chrome.storage.sync");
        }
        const response = await fetch(url, {
          method: "GET",
          credentials: "include",
          headers: {
            Authorization: `Bearer ${accessToken}`,
            "Content-Type": "application/json"
          }
        });
        if (response.ok) {
          const data = await response.json();
          const items = data.items || [];
          if (lastSyncedDate && items.length > 0) {
            const oldItemCount = items.filter((item) => {
              const updatedAt = new Date(
                item.update_time || item.updateTime || item.create_time || item.createTime
              );
              return !isNaN(updatedAt.getTime()) && updatedAt <= lastSyncedDate;
            }).length;
            if (oldItemCount > items.length * 0.7) {
              return items;
            }
          }
          if (data.cursor) {
            const nextBatch = await getProjectConversationsPerCursor(data.cursor);
            return items.concat(nextBatch);
          }
          return items;
        } else {
          return [];
        }
      } catch (err) {
        return [];
      }
    }
    return getProjectConversationsPerCursor();
  }
